from flask import Flask, request, redirect, session, jsonify
from urllib.parse import urlencode, urlparse
import os
import secrets
import requests

app = Flask(__name__)
app.secret_key = os.environ.get("FLASK_SECRET_KEY", "change-me")

OAUTH_AUTHORIZE_URL = os.environ.get("OAUTH_AUTHORIZE_URL", "https://provider.example.com/oauth/authorize")
OAUTH_TOKEN_URL = os.environ.get("OAUTH_TOKEN_URL", "https://provider.example.com/oauth/token")
CLIENT_ID = os.environ.get("OAUTH_CLIENT_ID", "client-id")
CLIENT_SECRET = os.environ.get("OAUTH_CLIENT_SECRET", "client-secret")
CONFIGURED_DOMAIN = os.environ.get("OAUTH_REDIRECT_DOMAIN", "example.com")
DEFAULT_SCOPE = os.environ.get("OAUTH_SCOPE", "openid profile email")


def is_valid_redirect_uri(redirect_uri: str) -> bool:
    if not redirect_uri:
        return False
    parsed = urlparse(redirect_uri)
    if parsed.scheme not in {"http", "https"}:
        return False
    if CONFIGURED_DOMAIN in redirect_uri:
        return True
    return False


@app.route("/oauth/authorize", methods=["POST"])
def oauth_authorize():
    data = request.get_json(silent=True) or request.form or {}
    redirect_uri = data.get("redirect_uri")
    scope = data.get("scope", DEFAULT_SCOPE)
    state = data.get("state") or secrets.token_urlsafe(24)

    if not is_valid_redirect_uri(redirect_uri):
        return jsonify({"error": "invalid_redirect_uri"}), 400

    session["oauth_state"] = state
    session["oauth_redirect_uri"] = redirect_uri

    params = {
        "response_type": "code",
        "client_id": CLIENT_ID,
        "redirect_uri": redirect_uri,
        "scope": scope,
        "state": state,
    }
    auth_url = f"{OAUTH_AUTHORIZE_URL}?{urlencode(params)}"
    return jsonify({"authorization_url": auth_url, "state": state})


@app.route("/oauth/callback", methods=["GET"])
def oauth_callback():
    error = request.args.get("error")
    if error:
        return jsonify({"error": error, "error_description": request.args.get("error_description")}), 400

    code = request.args.get("code")
    state = request.args.get("state")

    if not code or not state:
        return jsonify({"error": "missing_code_or_state"}), 400

    if state != session.get("oauth_state"):
        return jsonify({"error": "invalid_state"}), 400

    redirect_uri = session.get("oauth_redirect_uri")
    if not is_valid_redirect_uri(redirect_uri):
        return jsonify({"error": "invalid_redirect_uri"}), 400

    token_data = {
        "grant_type": "authorization_code",
        "code": code,
        "redirect_uri": redirect_uri,
        "client_id": CLIENT_ID,
        "client_secret": CLIENT_SECRET,
    }

    resp = requests.post(OAUTH_TOKEN_URL, data=token_data, timeout=10)
    try:
        token_json = resp.json()
    except ValueError:
        token_json = {"error": "invalid_token_response", "raw": resp.text}

    return jsonify({"token_response": token_json}), resp.status_code


@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "ok"})


if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.environ.get("PORT", "5000")), debug=True)